class Solution:
    def maxSubarraySum(self, nums):
        def kadane(arr):
            best = arr[0]
            cur = arr[0]
            for v in arr[1:]:
                cur = max(v, cur + v)
                best = max(best, cur)
            return best

        ans = kadane(nums)
        for x in set(nums):
            filtered = [v for v in nums if v != x]
            if filtered:
                ans = max(ans, kadane(filtered))
        return ans

