from collections import defaultdict

NEG_INF = float('-inf')


class _SegTree:
    def __init__(self, arr):
        self.n = len(arr)
        self.tree = [None] * (4 * self.n)
        self._build(arr, 1, 0, self.n - 1)

    def _build(self, arr, node, l, r):
        if l == r:
            v = arr[l]
            self.tree[node] = (v, v, v, v)
            return
        mid = (l + r) // 2
        self._build(arr, node * 2, l, mid)
        self._build(arr, node * 2 + 1, mid + 1, r)
        self.tree[node] = _SegTree.merge(self.tree[node * 2], self.tree[node * 2 + 1])

    @staticmethod
    def merge(a, b):
        if a is None:
            return b
        if b is None:
            return a
        s = a[0] + b[0]
        pre = max(a[1], a[0] + b[1])
        suf = max(b[2], b[0] + a[2])
        sub = max(a[3], b[3], a[2] + b[1])
        return (s, pre, suf, sub)

    def query(self, l, r, node=1, nl=0, nr=None):
        if nr is None:
            nr = self.n - 1
        if r < nl or nr < l:
            return None
        if l <= nl and nr <= r:
            return self.tree[node]
        mid = (nl + nr) // 2
        left = self.query(l, r, node * 2, nl, mid)
        right = self.query(l, r, node * 2 + 1, mid + 1, nr)
        return _SegTree.merge(left, right)


class Solution:
    def maxSubarraySum(self, nums):
        n = len(nums)
        st = _SegTree(nums)
        ans = st.query(0, n - 1)[3]
        pos = defaultdict(list)
        for i, v in enumerate(nums):
            if v < 0:
                pos[v].append(i)
        ZERO = (0, NEG_INF, NEG_INF, NEG_INF)
        for v, idxs in pos.items():
            if len(idxs) == n:
                continue
            blocks = []
            prev = -1
            for idx in idxs:
                lo, hi = prev + 1, idx - 1
                if lo <= hi:
                    blocks.append(st.query(lo, hi))
                blocks.append(ZERO)
                prev = idx
            lo, hi = prev + 1, n - 1
            if lo <= hi:
                blocks.append(st.query(lo, hi))
            merged = None
            for b in blocks:
                merged = b if merged is None else _SegTree.merge(merged, b)
            ans = max(ans, merged[3])
        return ans

