function segBuild(arr, node, l, r, tree) {
    if (l === r) {
        const v = arr[l];
        tree[node] = [v, v, v, v];
        return;
    }
    const mid = (l + r) >> 1;
    segBuild(arr, node * 2, l, mid, tree);
    segBuild(arr, node * 2 + 1, mid + 1, r, tree);
    tree[node] = segMerge(tree[node * 2], tree[node * 2 + 1]);
}
function segMerge(a, b) {
    if (a === null) return b;
    if (b === null) return a;
    const s = a[0] + b[0];
    const pre = Math.max(a[1], a[0] + b[1]);
    const suf = Math.max(b[2], b[0] + a[2]);
    const sub = Math.max(a[3], b[3], a[2] + b[1]);
    return [s, pre, suf, sub];
}
function segQuery(tree, n, l, r, node, nl, nr) {
    if (r < nl || nr < l) return null;
    if (l <= nl && nr <= r) return tree[node];
    const mid = (nl + nr) >> 1;
    const left = segQuery(tree, n, l, r, node * 2, nl, mid);
    const right = segQuery(tree, n, l, r, node * 2 + 1, mid + 1, nr);
    return segMerge(left, right);
}
var maxSubarraySum = function(nums) {
    const n = nums.length;
    const tree = new Array(4 * n).fill(null);
    segBuild(nums, 1, 0, n - 1, tree);
    let ans = segQuery(tree, n, 0, n - 1, 1, 0, n - 1)[3];
    const pos = new Map();
    for (let i = 0; i < n; i++) {
        if (nums[i] < 0) {
            if (!pos.has(nums[i])) pos.set(nums[i], []);
            pos.get(nums[i]).push(i);
        }
    }
    const ZERO = [0, -Infinity, -Infinity, -Infinity];
    for (const [v, idxs] of pos) {
        if (idxs.length === n) continue;
        const blocks = [];
        let prev = -1;
        for (const idx of idxs) {
            const lo = prev + 1, hi = idx - 1;
            if (lo <= hi) blocks.push(segQuery(tree, n, lo, hi, 1, 0, n - 1));
            blocks.push(ZERO);
            prev = idx;
        }
        const lo = prev + 1, hi = n - 1;
        if (lo <= hi) blocks.push(segQuery(tree, n, lo, hi, 1, 0, n - 1));
        let merged = null;
        for (const b of blocks) merged = merged === null ? b : segMerge(merged, b);
        ans = Math.max(ans, merged[3]);
    }
    return ans;
};
